            if (const auto *CDV = dyn_cast<ConstantDataVector>(C)) {
              for (unsigned i = 0, e = CDV->getNumElements(); i != e; ++i)
                if (HasDenormal(CDV->getElementAsConstant(i)))
                  return true;
            }
            return false;
          };

          if (HasDenormal(C1) || HasDenormal(C2))
            goto NotConstant;
        }
      }
    }
  }
